mapper.update:
UPDATE POST_REPORT

SET STATUS = #{resultStatus}

WHERE POST_ID = #{postId}
  AND REPORT_ID = #{reportId}
  AND STATUS = 'WAITING'

mapper.select:
SELECT FILE_PATH

FROM POST_ATTACHMENT

WHERE POST_ID = #{postId}

mapper.delete:
DELETE FROM COMMENT_REPORT

WHERE COMMENT_ID IN (
    SELECT COMMENT_ID
    FROM POST_COMMENT
    WHERE POST_ID = #{postId}
)

DELETE FROM COMMENT_LIKE

WHERE COMMENT_ID IN (
    SELECT COMMENT_ID
    FROM POST_COMMENT
    WHERE POST_ID = #{postId}
)
